C.a7z=new X.bs(0,C.au,"A Pawn is Worth a Thousand Generals","Ippu Atai Senkin",C.On)
C.a59=new Q.h("When your opponent attacks with a promoted Rook, remember that a Pawn-anchored Gold makes a solid guard.")
